2500 PreservedAnalyses NoRecurseLTOInferencePass::run(Module &M,
2501                                                  ModuleAnalysisManager &MAM) {
2502 
2503   // Check if any function in the whole program has its address taken or has
2504   // potentially external linkage.
2505   // We use this information when inferring norecurse attribute: If there is
2506   // no function whose address is taken and all functions have internal
2507   // linkage, there is no path for a callback to any user function.
2508   bool AnyFunctionsAddressIsTaken = false;
2509   for (Function &F : M) {
2510     if (F.isDeclaration() || F.doesNotRecurse())
2511       continue;
2512     if (!F.hasLocalLinkage() || F.hasAddressTaken()) {
2513       AnyFunctionsAddressIsTaken = true;
2514       break;
2515     }
2516   }
2517 
2518   // Run norecurse inference on all RefSCCs in the LazyCallGraph for this
2519   // module.
2520   bool Changed = false;
2521   LazyCallGraph &CG = MAM.getResult<LazyCallGraphAnalysis>(M);
2522   CG.buildRefSCCs();
2523 
2524   for (LazyCallGraph::RefSCC &RC : CG.postorder_ref_sccs()) {
2525     // Skip any RefSCC that is part of a call cycle. A RefSCC containing more
2526     // than one SCC indicates a recursive relationship involving indirect calls.
2527     if (RC.size() > 1)
2528       continue;
2529 
2530     // RefSCC contains a single-SCC. SCC size > 1 indicates mutually recursive
2531     // functions. Ex: foo1 -> foo2 -> foo3 -> foo1.
2532     LazyCallGraph::SCC &S = *RC.begin();
2533     if (S.size() > 1)
2534       continue;
2535 
2536     // Get the single function from this SCC.
2537     Function &F = S.begin()->getFunction();
2538     if (!F.hasExactDefinition() || F.doesNotRecurse())
2539       continue;
2540 
2541     // If the analysis confirms that this function has no recursive calls
2542     // (either direct, indirect, or through external linkages),
2543     // we can safely apply the norecurse attribute.
2544     if (!mayHaveRecursiveCallee(F, AnyFunctionsAddressIsTaken)) {
2545       F.setDoesNotRecurse();
2546       ++NumNoRecurse;
2547       Changed = true;
2548     }
2549   }
2550 
2551   PreservedAnalyses PA;
2552   if (Changed)
2553     PA.preserve<LazyCallGraphAnalysis>();
2554   else
2555     PA = PreservedAnalyses::all();
2556   return PA;
2557 }
